module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);
    reg [3:0] mul_en_out_reg;
    reg [7:0] mul_a_reg;
    reg [7:0] mul_b_reg;
    reg [15:0] sum [0:7];
    reg [15:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if(~rst_n) begin
            mul_en_out_reg <= 4'b0;
        end else begin
            mul_en_out_reg <= {mul_en_out_reg[2:0], mul_en_in};
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(~rst_n) begin
            mul_a_reg <= 8'b0;
            mul_b_reg <= 8'b0;
        end else if(mul_en_out_reg[0]) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end

    wire [7:0] temp[0:7];
    genvar i;
    generate
        for(i=0;i<8;i=i+1) begin: pp_gen
            assign temp[i] = (mul_b_reg[i]==1'b1)?(mul_a_reg>>i):8'b0;
        end
    endgenerate

    always @(posedge clk or negedge rst_n) begin
        if(~rst_n) begin
            sum[0] <= 16'b0;
            sum[1] <= 16'b0;
            sum[2] <= 16'b0;
            sum[3] <= 16'b0;
            sum[4] <= 16'b0;
            sum[5] <= 16'b0;
            sum[6] <= 16'b0;
            sum[7] <= 16'b0;
        end else begin
            sum[0] <= temp[0];
            sum[1] <= sum[0] + temp[1];
            sum[2] <= sum[1] + temp[2];
            sum[3] <= sum[2] + temp[3];
            sum[4] <= sum[3] + temp[4];
            sum[5] <= sum[4] + temp[5];
            sum[6] <= sum[5] + temp[6];
            sum[7] <= sum[6] + temp[7];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(~rst_n) begin
            mul_out_reg <= 16'b0;
        end else begin
            mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5] + sum[6] + sum[7];
        end
    end

    assign mul_out = (mul_en_out_reg[3])?mul_out_reg:16'b0;
endmodule
